// components/HomeCategories/index.tsx
"use client"; // Make sure this is here if using hooks
import Image from "next/image";
import Link from "next/link";
import styles from "./styles.module.scss"; // Create this CSS file

// Import icons (make sure the paths are correct)
import mobile from "@/app/assets/images/iconHomeCategories/mobile.png";
import tablet from "@/app/assets/images/iconHomeCategories/table.png";
import laptop from "@/app/assets/images/iconHomeCategories/laptop.png";
import tv from "@/app/assets/images/iconHomeCategories/tv.png";
import accessories from "@/app/assets/images/iconHomeCategories/game.png";
import smartwatch from "@/app/assets/images/iconHomeCategories/smartwatch.png";
import headphone from "@/app/assets/images/iconHomeCategories/headphone.png";
import repair from "@/app/assets/images/iconHomeCategories/repair.png";

const HomeCategories = () => {
  return (
    <div className={styles.categoriesContainer}>
      <Link href="#" className={styles.categoryItem}>
        <Image src={mobile} alt="Điện thoại" width={30} height={30} />
        <span>Điện thoại</span>
      </Link>
      <Link href="#" className={styles.categoryItem}>
        <Image src={tablet} alt="Máy tính bảng" width={30} height={30} />
        <span>Máy tính bảng</span>
      </Link>
      <Link href="#" className={styles.categoryItem}>
        <Image src={laptop} alt="Laptop" width={30} height={30} />
        <span>Laptop</span>
      </Link>
      <Link href="#" className={styles.categoryItem}>
        <Image src={tv} alt="Tivi" width={30} height={30} />
        <span>Tivi</span>
      </Link>
      <Link href="#" className={styles.categoryItem}>
        <Image src={accessories} alt="Phụ kiện" width={30} height={30} />
        <span>Phụ kiện</span>
      </Link>
      <Link href="#" className={styles.categoryItem}>
        <Image
          src={smartwatch}
          alt="Đồng hồ thông minh"
          width={30}
          height={30}
        />
        <span>Đồng hồ thông minh</span>
      </Link>
      <Link href="#" className={styles.categoryItem}>
        <Image src={headphone} alt="Tai nghe" width={30} height={30} />
        <span>Tai nghe</span>
      </Link>
      <Link href="#" className={styles.categoryItem}>
        <Image src={repair} alt="Sửa chữa" width={30} height={30} />
        <span>Sửa chữa</span>
      </Link>
    </div>
  );
};

export default HomeCategories;
